    function isSpecialNumber(num) {
        const s = num.toString();
        // Check if it's a palindrome
        if (s !== s.split('').reverse().join('')) {
            return false;
        }
        const count = {};
        for (const c of s) {
            const digit = parseInt(c, 10);
            if (digit < 1 || digit > 9) {
                return false;
